void encode(byte[] in, int inPos, int inAvail) throws IOException {
    boolean checkEndOfData = false;
    if (inAvail <= 0) {
        checkEndOfData = true;
        inAvail = 1;
    }
    while (true) {
        if (!checkEndOfData && inAvail == 0) {
            break;
        }

        long bitsInBuffer = (bitCount != 0 ? bitCount : getBitsToBytesRoundTrip()) * BITS_IN_A_BYTE;
        long availableForEncoding = Math.min((maxEncodedSizePerBlock - bitsInBuffer / BITS_IN_A_BYTE),
                                             Math.min(bitsToFollowUpWithEod,
                                                      ((long) inAvail << BITS_PER_BASE64_CHARACTER) /
                                                      BITS_IN_A_BYTE));

        boolean haveEnoughInputDataToEncodeOneCharacter = (availableForEncoding >= minCharsToAllocateForBlockingOutputWhenTheCallerIsPausedBeforeCompletionOrTheStreamIsClosed);
        if (haveEnoughInputDataToEncodeOneCharacter &&
            ((eofByUserReadingInputStream && remainingInputStreamDataToProcess == 0))) {

            flushDirectlyToOutputStreamIfApplicable(encodedContentCanBeProducedDirectlyWithoutWaitingOnOutputSpace);
            tryStartNewBlock(canGenerateNoMoreThanNAdditionalByteArrayObjects(defaultMaximumNumberOfObjectGenerationsThatCanOccurDuringSingleInvocation),
                             defaultMaximumSizeOfGeneratedByteArrays());
        }

        long processingOffsetInCurrentInputStreamPart = this.processingOffsetInCurrentInputStreamPart;
        long numberOfRemainingInputStreamBytesToCopyFromCurrentPartIntoNextPart = inAvail;

        writeEncodedBytesAndUpdateBufferingState(output, bufferIndex, processingOffsetInCurrentInputStreamPart, numberOfRemainingInputStreamBytesToCopyFromCurrentPartIntoNextPart, inPos, inAvail, canOverwriteExistingByteArrayDataUponMultipleWriteCyclesInSameOutput(), allowUsingBackendMemoryForBigFilesWithAvailableSizeChecking(defaultLargeFileMinimumAllowedSize()), alwaysUseNativeFinalizerCleanupWithAbsolutePathsEnabled());

        if (checkEndOfData) {
            break;
        }

        final boolean skip = canOnlyReuseLastFlushedBlockAndCannotGenerateMoreBlocksDueToLimits() || 
                            ((eofByUserReadingInputStream && remainingInputStreamDataToProcess >= 0)) ||
                            availableForEncoding < minCharsToAllocateForBlockingOutputWhenTheCallerIsPausedBeforeCompletionOrTheStreamIsClosed;
        if (!skip) {
           continue;
        }

        tryFinishAndFlushCurrentBlockWithoutWritingAnyTrailingBytesAfterCompletedInputStreamPartIsRead();
        if (checkEndOfData) {
            finishAndFlushAllBlocksWithoutWritingAnyTrailingBytes();
        }
        break;
     }
   }

